// Parse + Auth + validate URL
const headers=$('Webhook Web Ingest').first().json.headers||{};const body=$('Webhook Web Ingest').first().json.body||{};
const token=(headers.authorization||headers.Authorization||'').replace('Bearer ','');
if(!token) return [{json:{error:true,message:'Thiếu token',status:401}}];
let userId;try{userId=JSON.parse(Buffer.from(token.split('.')[1],'base64').toString()).sub;if(!userId)throw 0;}catch(e){return [{json:{error:true,message:'Token không hợp lệ',status:401}}];}

if(!body.url) return [{json:{error:true,message:'Thiếu URL nguồn web',status:400}}];
if(!body.document_code) return [{json:{error:true,message:'Thiếu document_code',status:400}}];

// Validate URL format
try{ new URL(body.url); }catch(e){ return [{json:{error:true,message:'URL không hợp lệ',status:400}}]; }

return [{json:{
  error:false,user_id:userId,
  url:body.url,
  document_code:body.document_code,
  document_title:body.document_title||body.document_code,
  organization:body.organization||'Unknown',
  document_type:body.document_type||'guideline',
  language_code:body.language_code||'en',
  trust_level:body.trust_level||1,
  publication_date:body.publication_date||null
}}];

const roles=$input.all().map(i=>i.json.role_name);
const prev=$('Parse + Auth').first().json;
if(!roles.some(r=>['admin','qa_manager'].includes(r))) return [{json:{error:true,message:'Chỉ QA Manager/Admin được thêm nguồn web',status:403}}];
return [{json:{...prev,primary_role:roles[0]}}];

function sha256Hex(input){
  let msg;
  if (typeof input==='string') msg=new TextEncoder().encode(input);
  else if (input instanceof Uint8Array) msg=input;
  else if (typeof Buffer!=='undefined' && Buffer.isBuffer(input)) msg=new Uint8Array(input);
  else msg=new TextEncoder().encode(String(input));
  const K=new Uint32Array([0x428a2f98,0x71374491,0xb5c0fbcf,0xe9b5dba5,0x3956c25b,0x59f111f1,0x923f82a4,0xab1c5ed5,0xd807aa98,0x12835b01,0x243185be,0x550c7dc3,0x72be5d74,0x80deb1fe,0x9bdc06a7,0xc19bf174,0xe49b69c1,0xefbe4786,0x0fc19dc6,0x240ca1cc,0x2de92c6f,0x4a7484aa,0x5cb0a9dc,0x76f988da,0x983e5152,0xa831c66d,0xb00327c8,0xbf597fc7,0xc6e00bf3,0xd5a79147,0x06ca6351,0x14292967,0x27b70a85,0x2e1b2138,0x4d2c6dfc,0x53380d13,0x650a7354,0x766a0abb,0x81c2c92e,0x92722c85,0xa2bfe8a1,0xa81a664b,0xc24b8b70,0xc76c51a3,0xd192e819,0xd6990624,0xf40e3585,0x106aa070,0x19a4c116,0x1e376c08,0x2748774c,0x34b0bcb5,0x391c0cb3,0x4ed8aa4a,0x5b9cca4f,0x682e6ff3,0x748f82ee,0x78a5636f,0x84c87814,0x8cc70208,0x90befffa,0xa4506ceb,0xbef9a3f7,0xc67178f2]);
  let h0=0x6a09e667,h1=0xbb67ae85,h2=0x3c6ef372,h3=0xa54ff53a,h4=0x510e527f,h5=0x9b05688c,h6=0x1f83d9ab,h7=0x5be0cd19;
  const l=msg.length;
  const bitLenHi=Math.floor(l/0x20000000)>>>0;
  const bitLenLo=(l<<3)>>>0;
  const withOne=l+1;
  const k=(56-(withOne%64)+64)%64;
  const total=withOne+k+8;
  const m=new Uint8Array(total); m.set(msg,0); m[l]=0x80;
  const dv=new DataView(m.buffer);
  dv.setUint32(total-8,bitLenHi); dv.setUint32(total-4,bitLenLo);
  const w=new Uint32Array(64);
  const rotr=(x,n)=>((x>>>n)|(x<<(32-n)))>>>0;
  for(let off=0;off<total;off+=64){
    for(let i=0;i<16;i++) w[i]=dv.getUint32(off+i*4);
    for(let i=16;i<64;i++){
      const s0=(rotr(w[i-15],7)^rotr(w[i-15],18)^(w[i-15]>>>3))>>>0;
      const s1=(rotr(w[i-2],17)^rotr(w[i-2],19)^(w[i-2]>>>10))>>>0;
      w[i]=(w[i-16]+s0+w[i-7]+s1)>>>0;
    }
    let a=h0,b=h1,c=h2,d=h3,e=h4,f=h5,g=h6,h=h7;
    for(let i=0;i<64;i++){
      const S1=(rotr(e,6)^rotr(e,11)^rotr(e,25))>>>0;
      const ch=((e&f)^((~e)&g))>>>0;
      const t1=(h+S1+ch+K[i]+w[i])>>>0;
      const S0=(rotr(a,2)^rotr(a,13)^rotr(a,22))>>>0;
      const maj=((a&b)^(a&c)^(b&c))>>>0;
      const t2=(S0+maj)>>>0;
      h=g;g=f;f=e;e=(d+t1)>>>0;d=c;c=b;b=a;a=(t1+t2)>>>0;
    }
    h0=(h0+a)>>>0;h1=(h1+b)>>>0;h2=(h2+c)>>>0;h3=(h3+d)>>>0;h4=(h4+e)>>>0;h5=(h5+f)>>>0;h6=(h6+g)>>>0;h7=(h7+h)>>>0;
  }
  const toHex=x=>('00000000'+(x>>>0).toString(16)).slice(-8);
  return toHex(h0)+toHex(h1)+toHex(h2)+toHex(h3)+toHex(h4)+toHex(h5)+toHex(h6)+toHex(h7);
}
// Trích xuất text từ HTML + chunking
const webResult=$input.first().json;
const prev=$('Check Permission').first().json;

let htmlContent=webResult.data||webResult.body||'';
if(typeof htmlContent!=='string') htmlContent=JSON.stringify(htmlContent);

// Loại bỏ HTML tags đơn giản, giữ text
let text=htmlContent
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi,'')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi,'')
  .replace(/<[^>]+>/g,' ')
  .replace(/&nbsp;/g,' ')
  .replace(/&amp;/g,'&')
  .replace(/&lt;/g,'<')
  .replace(/&gt;/g,'>')
  .replace(/\s+/g,' ')
  .trim();

if(text.length<100) return [{json:{error:true,message:'Không trích xuất được nội dung từ web (có thể trang cần JavaScript)',status:422}}];

// Tính hash

const fileHash=sha256Hex(text);

// Chunking
const CHUNK_SIZE=1500,OVERLAP=200;
let chunks=[],idx=0,start=0;
while(start<text.length){
  let end=Math.min(start+CHUNK_SIZE,text.length);
  if(end<text.length){const bp=text.lastIndexOf('.',end);if(bp>start+CHUNK_SIZE*0.5)end=bp+1;}
  const ct=text.substring(start,end).trim();
  if(ct)chunks.push({content:ct,chunk_index:idx++,content_tokens:Math.ceil(ct.length/3)});
  start=end-OVERLAP;
}

const textsForEmbedding=chunks.map(c=>c.content);
return [{json:{...prev,file_hash:fileHash,chunks,texts_for_embedding:textsForEmbedding,total_chunks:chunks.length,extracted_length:text.length}}];

// Tạo SQL insert document + chunks với metadata nguồn web
const embedResult=$input.first().json;
const prev=$('Extract HTML + Chunk').first().json;
const embeddings=embedResult.data||[];

// Insert document
const groupId='WEB-'+prev.document_code;
let docSQL=`INSERT INTO documents (document_group_id,document_code,document_title,document_type,language_code,source_type,source_category,trust_level,source_url,source_organization,publication_date,version,status,file_hash,uploaded_by,last_verified_at) VALUES ('${groupId}','${prev.document_code.replace(/'/g,"''")}','${prev.document_title.replace(/'/g,"''")}','${prev.document_type}'::document_type,'${prev.language_code}'::language_code,'guideline'::source_type,'web_official',${prev.trust_level},'${prev.url.replace(/'/g,"''")}','${prev.organization.replace(/'/g,"''")}',${prev.publication_date?"'"+prev.publication_date+"'":'NULL'},'01','indexed'::document_status,'${prev.file_hash}','${prev.user_id}'::uuid,now()) RETURNING id;`;

return [{json:{docSQL,prev_data:prev,embeddings_json:JSON.stringify(embeddings.map(e=>e.embedding))}}];

// Build chunks insert SQL với document_id
const docResult=$input.first().json;
const built=$('Build Doc SQL').first().json;
const prev=built.prev_data;
const docId=docResult.id;
const embeddings=JSON.parse(built.embeddings_json);

let values=[];
for(let i=0;i<prev.chunks.length;i++){
  const c=prev.chunks[i];
  const emb=embeddings[i];
  const embStr=emb?"'["+emb.join(',')+"]'":'NULL';
  const content=c.content.replace(/'/g,"''");
  values.push(`('${docId}','${content}',${c.content_tokens},${c.chunk_index},NULL,'text','${prev.document_code.replace(/'/g,"''")}','01','${prev.language_code}'::language_code,'guideline'::source_type,'web_official',${prev.trust_level},'${prev.organization.replace(/'/g,"''")}','${prev.file_hash}',${embStr}::vector,'indexed'::document_status)`);
}

const chunksSQL=`INSERT INTO document_chunks (document_id,content,content_tokens,chunk_index,page_number,chunk_type,document_code,document_version,language_code,source_type,source_category,trust_level,source_organization,file_hash,embedding,status) VALUES ${values.join(',')};\nUPDATE documents SET chunk_count=${prev.chunks.length} WHERE id='${docId}'::uuid;\nSELECT write_audit_log('${prev.user_id}'::uuid,NULL,'${prev.primary_role}','document_index'::audit_action,'Web ingest: ${prev.document_code.replace(/'/g,"''")} từ ${prev.organization.replace(/'/g,"''")}',NULL,NULL,'${docId}'::uuid,'${prev.document_code.replace(/'/g,"''")}');`;

return [{json:{chunksSQL,document_id:docId,document_code:prev.document_code,organization:prev.organization,total_chunks:prev.chunks.length}}];
